+package crdt
+
+import "testing"
+
+// TestORSet_MergeUnionTags checks that the same element added concurrently on
+// two replicas survives a bidirectional merge and is reported present.
+func TestORSet_MergeUnionTags(t *testing.T) {
+	a := NewORSet("a")
+	b := NewORSet("b")
+	a.Add("x")
+	b.Add("x")
+	a.Merge(b)
+	b.Merge(a)
+	if !a.Contains("x") {
+		t.Fatal("replica a should contain x after merge")
+	}
+	if !b.Contains("x") {
+		t.Fatal("replica b should contain x after merge")
+	}
+}
+
+// TestORSet_ContainsCorrect checks the basic membership contract.
+func TestORSet_ContainsCorrect(t *testing.T) {
+	s := NewORSet("n")
+	if s.Contains("missing") {
+		t.Fatal("empty set should not contain element")
+	}
+	s.Add("present")
+	if !s.Contains("present") {
+		t.Fatal("should contain added element")
+	}
+	s.Remove("present")
+	if s.Contains("present") {
+		t.Fatal("should not contain removed element")
+	}
+}
